class TextDataset(Dataset):
    def __init__(self, texts, tokenizer, max_length=128):
        self.encodings = tokenizer(
            texts,
            return_tensors="pt",
            add_special_tokens=True,
            padding="max_length",
            truncation=True,
            max_length=max_length,
        )

    def __len__(self):
        return self.encodings["input_ids"].shape[0]

    def __getitem__(self, idx):
        return {key: val[idx] for key, val in self.encodings.items()}

def get_dataloader(tokenizer, activation:bool, config):
    """activation = True means use the activation_text_corpus and False means coactivation_text_corpus"""
    device = config.device

    if activation:
        batch_size = config.activations_batch_size
        max_length = config.max_tokens_activation
        start_index = config.start_index_sample_text
        n_text_examples = (config.n_tokens_act_freq // max_length) + (1 if config.n_tokens_act_freq % max_length != 0 else 0)
        corpus = config.activation_text_corpus
    else:
        batch_size = config.coactivations_batch_size
        max_length = config.max_tokens_coactivation
        start_index = config.start_index_coact_text
        n_text_examples = (config.n_tokens_coacts // max_length) + (1 if config.n_tokens_coacts % max_length != 0 else 0)
        corpus = config.coactivation_text_corpus
    
    num_batches_to_process = n_text_examples // batch_size + (1 if n_text_examples % batch_size != 0 else 0)  
    end_index = start_index + num_batches_to_process * batch_size


    if corpus == "fineweb":
        data_path = config.CLT_dir / "data" / "fineweb_10bt_offline"
        return get_fineweb_dataloader(tokenizer, data_path, batch_size = batch_size, max_length = max_length, device = device, start_index = start_index, end_index = end_index)
    elif corpus == "dummy":
        return get_dummy_dataloader(tokenizer, batch_size, max_length, start_index, end_index)
    else:
        raise ValueError(f"Unknown corpus: {corpus}")
    


def get_dummy_dataloader(tokenizer, batch_size, max_length, start_index, end_index):
    dataset = TextDataset(DUMMY_TEXTS, tokenizer, max_length=max_length)
    shuffled_dataset = dataset.shuffle(seed=42)
    dataset = shuffled_dataset.select(range(start_index, end_index))
    return DataLoader(dataset, batch_size=batch_size, shuffle=False)


def get_fineweb_dataloader(tokenizer, data_path, batch_size=32, max_length=128, device = "cuda", start_index = 0, end_index = 1_171_875):
    """
    Args:
        tokenizer: Your generic tokenizer (e.g., GPT2Tokenizer)
        data_path: Path to local arrow folder OR huggingface dataset name
    """
    
    # 1. Load the dataset (Lazy load - does not read into RAM yet)
    dataset = load_from_disk(data_path)
    shuffled_dataset = dataset.shuffle(seed=42) # ensures the same shuffle for each run
    # dataset = shuffled_dataset.select(range(96704))
    dataset = shuffled_dataset.select(range(start_index, end_index)) 


    # 2. Define the collate function
    def collate_fn(batch_list):
        # Extract just the text strings from the dataset rows
        raw_texts = [item['text'] for item in batch_list]
        
        # Tokenize efficiently in a batch
        # This is faster than tokenizing one-by-one
        encodings = tokenizer(
            raw_texts,
            return_tensors="pt",
            padding="max_length", # Pad to max_length
            truncation=True,      # Truncate if longer than max_length
            max_length=max_length
        )
        
        return encodings

    # 3. Create the DataLoader
    # We pass the raw dataset directly. PyTorch handles the indices.
    dataloader = DataLoader(
        dataset, 
        batch_size=batch_size, 
        shuffle=True,       # Crucial for measuring features!
        collate_fn=collate_fn,
        num_workers=2,      # Speeds up tokenization using multiple cores
        pin_memory=True if device == "cuda" else False    # Speeds up transfer to GPU
    )
    
    return dataloader